#include <stdio.h>
#include <stdbool.h>
#define MAX_LEN 1005

bool isBalanced(const char *s) {
    int bal = 0;
    for (int i = 0; s[i]; ++i) {
        if (s[i] == '(') ++bal;
        else if (s[i] == ')') {
            if (bal == 0) return false;
            --bal;
        }
    }
    return bal == 0;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char str[MAX_LEN];
    while (T--) {
        scanf("%s", str);
        printf("%s : %s\n", str, isBalanced(str) ? "true" : "false");
    }
    return 0;
}

