import sys

def is_balanced(s: str) -> bool:
    bal = 0
    for ch in s:
        if ch == '(':
            bal += 1
        elif ch == ')':
            if bal == 0:
                return False
            bal -= 1
    return bal == 0

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        expr = data[i]
        out.append(f"{expr} : {str(is_balanced(expr)).lower()}")
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

